import { signal, computed, effect } from '@angular/core';

// A writable signal: always holds a current value.
const count = signal(0);

// Read: call it like a function. Returns the current value synchronously.
console.log(count()); // 0

// Write: set replaces, update derives from previous.
count.set(1);
count.update((c) => c + 1); // now 2

// A computed signal: derived, memoized, read-only.
const doubled = computed(() => count() * 2);
console.log(doubled()); // 4

// An effect: runs side effects when its dependencies change.
effect(() => console.log('count is', count()));

import { signal, computed } from '@angular/core';

const price = signal(100);
const quantity = signal(2);
const taxRate = signal(0.2);

// Dependencies are discovered by reading signals inside the function.
const subtotal = computed(() => price() * quantity());
const total = computed(() => subtotal() * (1 + taxRate()));

console.log(total()); // 240

quantity.set(3);
console.log(total()); // 360 -- subtotal and total both recomputed

// Reading total() again without any change returns the cached value.
console.log(total()); // 360 (no recomputation)

import { Component, signal, effect, inject, Injector, runInInjectionContext } from '@angular/core';

@Component({ selector: 'app-theme', standalone: true, template: '' })
export class ThemeComponent {
  readonly theme = signal<'light' | 'dark'>('light');

  constructor() {
    // Created in an injection context (constructor). Cleaned up on destroy.
    effect(() => {
      document.body.dataset['theme'] = this.theme();
      localStorage.setItem('theme', this.theme());
    });

    // Effects can register cleanup that runs before the next execution
    // and on destroy.
    effect((onCleanup) => {
      const id = setInterval(() => console.log(this.theme()), 1000);
      onCleanup(() => clearInterval(id));
    });
  }
}

import { Component, input, model, output, computed } from '@angular/core';

@Component({
  selector: 'app-user-card',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <h3>{{ displayName() }}</h3>
    <button (click)="toggle()">{{ expanded() ? 'Collapse' : 'Expand' }}</button>
    <button (click)="remove.emit(userId())">Remove</button>
  `
})
export class UserCardComponent {
  // Optional input with a default.
  readonly firstName = input('');
  // Required input: consumer must provide it or the template fails to compile.
  readonly userId = input.required<string>();
  // Transform input at the boundary.
  readonly lastName = input('', { transform: (v: string) => v.trim() });

  // Two-way bindable: <app-user-card [(expanded)]="isOpen" />
  readonly expanded = model(false);

  // Typed output, no @Output decorator.
  readonly remove = output<string>();

  // Inputs are signals, so they compose in computed().
  readonly displayName = computed(() => `${this.firstName()} ${this.lastName()}`.trim());

  toggle(): void {
    this.expanded.update((v) => !v);
  }
}

import { Component, signal, inject } from '@angular/core';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { HttpClient } from '@angular/common/http';
import { debounceTime, distinctUntilChanged, switchMap, startWith } from 'rxjs';

@Component({ selector: 'app-search', standalone: true, template: '' })
export class SearchComponent {
  private http = inject(HttpClient);

  // A signal drives the query.
  readonly query = signal('');

  // Convert the signal to a stream to use time-based operators + cancellation.
  private results$ = toObservable(this.query).pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((q) =>
      this.http.get<string[]>(`/api/search?q=${encodeURIComponent(q)}`)
    )
  );

  // Convert the stream back to a signal for the template.
  // requireSync:false so we can supply an initialValue safely.
  readonly results = toSignal(this.results$, { initialValue: [] as string[] });
}

