import { BehaviorSubject } from 'rxjs';

const source$ = new BehaviorSubject(0);

// Because BehaviorSubject emits synchronously, requireSync gives a
// non-nullable Signal<number> with no initialValue needed.
const value = toSignal(source$, { requireSync: true }); // Signal<number>

// Without requireSync/initialValue the type is Signal<number | undefined>.
const maybe = toSignal(source$); // Signal<number | undefined>

import { Component, ChangeDetectionStrategy, signal, computed } from '@angular/core';

@Component({
  selector: 'app-counter',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <p>Count: {{ count() }}</p>
    <p>Doubled: {{ doubled() }}</p>
    <button (click)="increment()">+1</button>
  `
})
export class CounterComponent {
  readonly count = signal(0);
  readonly doubled = computed(() => this.count() * 2);

  increment(): void {
    // No markForCheck needed. Reading count() in the template registered
    // a dependency; this write marks the view for refresh.
    this.count.update((c) => c + 1);
  }
}

