import { signal } from '@angular/core';

const items = signal<string[]>(['a']);

// WRONG: mutates in place, same reference, no notification.
items().push('b');
items.set(items()); // Object.is(prev, next) === true -> no update

// RIGHT: new reference each time.
items.update((list) => [...list, 'b']);

// Custom equality when reference changes but you want value equality.
const point = signal(
  { x: 0, y: 0 },
  { equal: (a, b) => a.x === b.x && a.y === b.y }
);
point.set({ x: 0, y: 0 }); // custom equal returns true -> no notification

import { Injectable, computed, signal } from '@angular/core';

export interface CartLine {
  readonly productId: string;
  readonly name: string;
  readonly unitPrice: number;
  readonly qty: number;
}

@Injectable({ providedIn: 'root' })
export class CartStore {
  // Private writable state.
  private readonly _lines = signal<ReadonlyArray<CartLine>>([]);
  private readonly _taxRate = signal(0.2);

  // Public read-only surface.
  readonly lines = this._lines.asReadonly();
  readonly itemCount = computed(() =>
    this._lines().reduce((n, l) => n + l.qty, 0)
  );
  readonly subtotal = computed(() =>
    this._lines().reduce((sum, l) => sum + l.unitPrice * l.qty, 0)
  );
  readonly tax = computed(() => this.subtotal() * this._taxRate());
  readonly total = computed(() => this.subtotal() + this.tax());
  readonly isEmpty = computed(() => this._lines().length === 0);

  add(line: Omit<CartLine, 'qty'>, qty = 1): void {
    this._lines.update((lines) => {
      const existing = lines.find((l) => l.productId === line.productId);
      if (existing) {
        return lines.map((l) =>
          l.productId === line.productId ? { ...l, qty: l.qty + qty } : l
        );
      }
      return [...lines, { ...line, qty }];
    });
  }

  setQty(productId: string, qty: number): void {
    if (qty <= 0) return this.remove(productId);
    this._lines.update((lines) =>
      lines.map((l) => (l.productId === productId ? { ...l, qty } : l))
    );
  }

  remove(productId: string): void {
    this._lines.update((lines) => lines.filter((l) => l.productId !== productId));
  }

  clear(): void {
    this._lines.set([]);
  }
}

