interface Filters { search: string; page: number; }

@Injectable({ providedIn: 'root' })
export class FiltersServiceRx {
  private readonly state$ = new BehaviorSubject<Filters>({ search: '', page: 1 });

  readonly filters$: Observable<Filters> = this.state$.asObservable();
  readonly search$ = this.state$.pipe(map((s) => s.search));

