interface Filters { search: string; page: number; }

@Injectable({ providedIn: 'root' })
export class FiltersService {
  // BehaviorSubject(initial)  ->  signal(initial)
  private readonly _state = signal<Filters>({ search: '', page: 1 });

  // asObservable()  ->  asReadonly()
  readonly filters = this._state.asReadonly();
  // pipe(map(...))  ->  computed(...)
  readonly search = computed(() => this._state().search);

  // .next({ ...value, ... })  ->  .update((s) => ({ ...s, ... }))
  setSearch(search: string): void {
    this._state.update((s) => ({ ...s, search, page: 1 }));
  }

  nextPage(): void {
    this._state.update((s) => ({ ...s, page: s.page + 1 }));
  }
}

// ANTI-PATTERN: effect that writes a signal it (transitively) reads.
const a = signal(0);
const b = signal(0);
effect(() => {
  // If b is derived from a, this belongs in a computed, not an effect.
  b.set(a() * 2); // requires allowSignalWrites; creates feedback risk
});

// CORRECT: derive with computed.
const bDerived = computed(() => a() * 2);

