import { Injectable, computed, signal } from '@angular/core';
import { toObservable } from '@angular/core/rxjs-interop';
import { Observable } from 'rxjs';

export interface Filters {
  readonly search: string;
  readonly page: number;
}

@Injectable({ providedIn: 'root' })
export class FiltersService {
  // BehaviorSubject(initial) -> signal(initial)
  private readonly _state = signal<Filters>({ search: '', page: 1 });

  // asObservable() -> asReadonly(); pipe(map(...)) -> computed(...)
  readonly filters = this._state.asReadonly();
  readonly search = computed(() => this._state().search);
  readonly page = computed(() => this._state().page);

  // Bridge for legacy RxJS pipelines that still need an Observable.
  readonly filters$: Observable<Filters> = toObservable(this.filters);

  // .next({ ...value, ... }) -> .update((s) => ({ ...s, ... }))
  setSearch(search: string): void {
    this._state.update((s) => ({ ...s, search, page: 1 }));
  }

  nextPage(): void {
    this._state.update((s) => ({ ...s, page: s.page + 1 }));
  }
}

